class ProductViewSet(viewsets.ModelViewSet):
    queryset = Product.objects.all()
    permission_classes = [IsAuthenticated]

    def get_queryset(self):
        return self.queryset.filter(
            organization=self.request.user.organization
        ).select_related('category').prefetch_related('tags')

    def get_serializer_class(self):
        if self.action == 'create':
            return CreateProductSerializer
        if self.action in ['update', 'partial_update']:
            return UpdateProductSerializer
        if self.action == 'list':
            return ProductListSerializer
        return ProductDetailSerializer

class PublishProductView(APIView):
    permission_classes = [IsAuthenticated]

    def post(self, request, pk: int):
        serializer = PublishProductSerializer(data=request.data)
        serializer.is_valid(raise_exception=True)
        try:
            result = product_services.publish(pk=pk, user=request.user)
        except product_services.ProductNotFound as e:
            return Response({'error': str(e)}, status=status.HTTP_404_NOT_FOUND)
        return Response(ProductSerializer(result).data, status=status.HTTP_200_OK)

class UserSerializer(serializers.ModelSerializer):
    class Meta:
        model = User
        fields = '__all__'  # Security risk: exposes password_hash, tokens, etc.

class CreateUserSerializer(serializers.Serializer):
    """Input: validate registration data."""
    email = serializers.EmailField()
    password = serializers.CharField(min_length=8, write_only=True)
    first_name = serializers.CharField(max_length=100)

    def validate_email(self, value: str) -> str:
        if User.objects.filter(email=value.lower()).exists():
            raise serializers.ValidationError("Email already registered")
        return value.lower()


class UserListSerializer(serializers.ModelSerializer):
    """Output: minimal fields for list views."""
    class Meta:
        model = User
        fields = ['id', 'uid', 'email', 'first_name', 'last_name']
        read_only_fields = fields


class UserDetailSerializer(serializers.ModelSerializer):
    """Output: full fields for detail views."""
    organization = OrganizationSerializer(read_only=True)

    class Meta:
        model = User
        fields = ['id', 'uid', 'email', 'first_name', 'last_name',
                  'organization', 'role', 'created_at']
        read_only_fields = fields

from ninja import Schema, ModelSchema
from pydantic import Field, field_validator

class CreateOrderSchema(Schema):
    amount: Decimal = Field(..., ge=0)
    item_id: int

    @field_validator('amount')
    @classmethod
    def amount_positive(cls, v: Decimal) -> Decimal:
        if v <= 0:
            raise ValueError("Amount must be positive")
        return v

class OrderSchema(ModelSchema):
    class Meta:
        model = Order
        fields = ['id', 'uid', 'amount', 'status', 'created_at']

class IsOrganizationMember(permissions.BasePermission):
    message = "You don't have access to this resource"

    def has_object_permission(self, request, view, obj) -> bool:
        if hasattr(obj, 'organization'):
            return obj.organization == request.user.organization
        if hasattr(obj, 'user'):
            return obj.user.organization == request.user.organization
        return False
